export const 鎮宅立塚 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.4) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：桿三
    線(p => p.M(X(1.0), Z(1.2)).L(X(6.1), Z(1.1)));
    圈(0.7, 1.2);
    圈(6.4, 1.1);
    線(p => p.M(X(1.0), Z(2.2)).L(X(6.1), Z(2.1)));
    圈(0.7, 2.2);
    圈(6.4, 2.1);
    線(p => p.M(X(1.0), Z(3.2)).L(X(6.1), Z(3.1)));
    圈(0.7, 3.2);
    圈(6.4, 3.1);
    // 右緣圈列
    圈(6.6, 4.2);
    圈(6.7, 5.3);
    圈(6.8, 6.4);
    圈(6.8, 7.5);
    // 人字圈鏈
    圈(3.6, 4.2);
    連([3.6, 4.2], [1.4, 5.2]);
    連([3.6, 4.2], [5.7, 5.2]);
    圈(1.4, 5.2);
    圈(5.7, 5.2);
    // 左朱形（摹形從簡）
    出(p => p.M(X(1.9), Z(5.7)).L(X(0.9), Z(6.15)), 0.32);
    線(p => p.M(X(0.8), Z(6.3)).L(X(2.5), Z(6.25)), 0.32);
    線(p => p.M(X(0.7), Z(7.0)).L(X(2.6), Z(6.95)), 0.32);
    線(p => p.M(X(1.7), Z(5.8)).L(X(1.68), Z(7.5)), 0.34);
    出(p => p.M(X(1.6), Z(7.0)).L(X(1.0), Z(7.6)), 0.3);
    出(p => p.M(X(1.75), Z(7.0)).L(X(2.4), Z(7.6)), 0.3);
    // 右三斗形（橫二＋斗點斜豎——摹形）
    線(p => p.M(X(2.6), Z(6.0)).L(X(4.3), Z(5.95)), 0.34);
    線(p => p.M(X(2.6), Z(6.7)).L(X(4.2), Z(6.65)), 0.34);
    線(p => p.M(X(4.6), Z(6.1)).L(X(4.9), Z(6.05)), 0.3);
    線(p => p.M(X(4.7), Z(6.9)).L(X(5.0), Z(6.85)), 0.3);
    線(p => p.M(X(4.5), Z(7.4)).L(X(5.8), Z(7.1)), 0.32);
    線(p => p.M(X(5.5), Z(5.7)).L(X(5.48), Z(7.9)), 0.36);
    // 左柱：橫承巳曲（開框）
    線(p => p.M(X(0.7), Z(8.1)).L(X(2.6), Z(8.05)), 0.36);
    出(p => p.M(X(2.4), Z(8.3))
        .C(X(1.3), Z(8.6), X(1.1), Z(9.2), X(1.8), Z(9.5))
        .C(X(2.3), Z(9.7), X(2.3), Z(9.9), X(1.9), Z(9.95)), 0.36);
    // 目箱三疊
    const 目 = (x0, x1, z0, z1) => {
        線(p => p.M(X(x0), Z(z0)).L(X(x0), Z(z1)).L(X(x1), Z(z1 - 0.05))
            .L(X(x1), Z(z0 - 0.05)).L(X(x0 - 0.05), Z(z0)));
        線(p => p.M(X(x0 + 0.1), Z((z0 + z1) / 2)).L(X(x1 - 0.1), Z((z0 + z1) / 2 - 0.03)), 0.32);
    };
    目(0.8, 3.2, 10.0, 12.2);
    目(0.8, 3.2, 12.6, 14.8);
    目(0.8, 3.2, 15.2, 17.4);
    // 右柱：尸目框
    線(p => p.M(X(3.9), Z(7.9)).L(X(6.6), Z(7.85)), 0.36);
    線(p => p.M(X(4.0), Z(7.9)).L(X(3.95), Z(10.3)), 0.36);
    線(p => p.M(X(4.6), Z(8.5)).L(X(4.6), Z(10.1)).L(X(6.4), Z(10.05))
        .L(X(6.4), Z(8.45)).L(X(4.55), Z(8.5)), 0.32);
    線(p => p.M(X(4.7), Z(9.3)).L(X(6.3), Z(9.27)), 0.3);
    // 田箱（內十）
    線(p => p.M(X(4.2), Z(10.8)).L(X(4.2), Z(12.7)).L(X(6.4), Z(12.65))
        .L(X(6.4), Z(10.75)).L(X(4.15), Z(10.8)), 0.34);
    線(p => p.M(X(5.3), Z(10.85)).L(X(5.28), Z(12.6)), 0.3);
    線(p => p.M(X(4.3), Z(11.75)).L(X(6.3), Z(11.72)), 0.3);
    // 目箱
    目(4.2, 6.5, 13.0, 15.4);
    // 月門框（內桁二，雙足下曳）
    出(p => p.M(X(4.3), Z(15.9)).C(X(4.28), Z(16.9), X(4.25), Z(17.9), X(4.1), Z(18.6)), 0.36);
    線(p => p.M(X(4.3), Z(16.0)).L(X(6.4), Z(15.95)), 0.34);
    出(p => p.M(X(6.4), Z(15.95)).L(X(6.37), Z(18.6)), 0.36);
    線(p => p.M(X(4.4), Z(17.0)).L(X(6.3), Z(16.95)), 0.3);
    線(p => p.M(X(4.3), Z(17.8)).L(X(6.3), Z(17.75)), 0.3);
    // 底合形（人字承桁——摹形從簡）
    出(p => p.M(X(1.6), Z(17.9)).L(X(0.75), Z(19.0)), 0.34);
    出(p => p.M(X(1.7), Z(17.9)).L(X(2.55), Z(19.0)), 0.34);
    線(p => p.M(X(1.1), Z(19.15)).L(X(2.2), Z(19.1)), 0.32);
};
